import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../App';
import './WorkshopTypesPage.css';

const WORKSHOPS = [
  { id: 1, name: 'Python', duration: 2, emoji: '🐍', desc: 'Scripting, data analysis and automation', tags: ['Programming', 'Data Science'] },
  { id: 2, name: 'Scilab', duration: 3, emoji: '📐', desc: 'Numerical computing and simulation for engineering', tags: ['Engineering', 'Math'] },
  { id: 3, name: 'OpenFOAM', duration: 5, emoji: '💨', desc: 'Computational fluid dynamics and FEA simulations', tags: ['Engineering', 'Simulation'] },
  { id: 4, name: 'DWSIM', duration: 2, emoji: '⚗️', desc: 'Chemical process simulation and thermodynamics', tags: ['Chemical', 'Simulation'] },
  { id: 5, name: 'eSim', duration: 3, emoji: '⚡', desc: 'Electronics design and SPICE circuit simulation', tags: ['Electronics', 'Design'] },
  { id: 6, name: 'R', duration: 2, emoji: '📊', desc: 'Statistical computing and data visualisation', tags: ['Statistics', 'Data Science'] },
  { id: 7, name: 'Arduino', duration: 2, emoji: '🤖', desc: 'Embedded systems and IoT programming', tags: ['Electronics', 'IoT'] },
  { id: 8, name: 'LaTeX', duration: 1, emoji: '📝', desc: 'Scientific document preparation system', tags: ['Writing', 'Research'] },
];

export default function WorkshopTypesPage() {
  const { user } = useAuth();
  const [search, setSearch] = useState('');
  const [filter, setFilter] = useState('All');

  const allTags = ['All', ...new Set(WORKSHOPS.flatMap(w => w.tags))];

  const filtered = WORKSHOPS.filter(w => {
    const matchSearch = w.name.toLowerCase().includes(search.toLowerCase()) ||
      w.desc.toLowerCase().includes(search.toLowerCase());
    const matchFilter = filter === 'All' || w.tags.includes(filter);
    return matchSearch && matchFilter;
  });

  return (
    <div className="wt-page">
      <div className="container">
        <div className="page-header">
          <h1>Workshop Types</h1>
          <p>Explore all available workshops. Each is conducted by expert instructors from IIT Bombay.</p>
        </div>

        {/* Search & Filter */}
        <div className="wt-toolbar" role="search">
          <div className="search-wrapper">
            <svg className="search-icon" width="16" height="16" viewBox="0 0 16 16" fill="none" aria-hidden="true">
              <circle cx="6.5" cy="6.5" r="4.5" stroke="currentColor" strokeWidth="1.5"/>
              <path d="M10.5 10.5L14 14" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
            </svg>
            <input
              className="form-control search-input"
              type="search"
              placeholder="Search workshops…"
              value={search}
              onChange={e => setSearch(e.target.value)}
              aria-label="Search workshops"
            />
          </div>
          <div className="filter-tags" role="group" aria-label="Filter by category">
            {allTags.map(tag => (
              <button
                key={tag}
                className={`filter-tag${filter === tag ? ' active' : ''}`}
                onClick={() => setFilter(tag)}
                aria-pressed={filter === tag}
              >
                {tag}
              </button>
            ))}
          </div>
        </div>

        {/* Results count */}
        <p className="results-count" aria-live="polite">
          {filtered.length} workshop{filtered.length !== 1 ? 's' : ''} found
        </p>

        {/* Table on desktop, Cards on mobile */}
        <div className="wt-table-wrapper card" role="table" aria-label="Available workshops">
          <table className="data-table wt-table" role="table">
            <thead>
              <tr>
                <th scope="col" style={{width:'48px'}}></th>
                <th scope="col">Workshop Name</th>
                <th scope="col">Description</th>
                <th scope="col">Duration</th>
                <th scope="col">Tags</th>
                <th scope="col" style={{textAlign:'right'}}>Action</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map(w => (
                <tr key={w.id}>
                  <td><span style={{fontSize:'20px'}} aria-hidden="true">{w.emoji}</span></td>
                  <td>
                    <span style={{fontWeight:600, color:'var(--text-primary)', fontFamily:'var(--font-display)'}}>
                      {w.name}
                    </span>
                  </td>
                  <td style={{maxWidth:'280px'}}>{w.desc}</td>
                  <td>
                    <span className="badge badge-info">{w.duration} Day{w.duration > 1 ? 's' : ''}</span>
                  </td>
                  <td>
                    <div style={{display:'flex', gap:'6px', flexWrap:'wrap'}}>
                      {w.tags.map(t => (
                        <span key={t} style={{fontSize:'11px', color:'var(--text-muted)', background:'rgba(255,255,255,0.04)', padding:'2px 8px', borderRadius:'100px', border:'1px solid var(--border)'}}>
                          {t}
                        </span>
                      ))}
                    </div>
                  </td>
                  <td style={{textAlign:'right'}}>
                    <Link to={`/workshop-types/${w.id}`} className="btn btn-outline btn-sm">
                      Details →
                    </Link>
                  </td>
                </tr>
              ))}
              {filtered.length === 0 && (
                <tr>
                  <td colSpan="6" style={{textAlign:'center', padding:'48px', color:'var(--text-muted)'}}>
                    No workshops found for "{search}"
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        {/* Mobile cards */}
        <div className="wt-mobile-cards" role="list" aria-label="Available workshops">
          {filtered.map(w => (
            <Link key={w.id} to={`/workshop-types/${w.id}`} className="wt-mobile-card" role="listitem">
              <div className="wt-mobile-card-top">
                <span className="wt-mobile-emoji" aria-hidden="true">{w.emoji}</span>
                <div>
                  <div className="wt-mobile-name">{w.name}</div>
                  <span className="badge badge-info">{w.duration} Day{w.duration > 1 ? 's' : ''}</span>
                </div>
              </div>
              <p className="wt-mobile-desc">{w.desc}</p>
              <div className="wt-mobile-footer">
                <div style={{display:'flex', gap:'6px', flexWrap:'wrap'}}>
                  {w.tags.map(t => (
                    <span key={t} style={{fontSize:'11px', color:'var(--text-muted)', background:'rgba(255,255,255,0.04)', padding:'2px 8px', borderRadius:'100px', border:'1px solid var(--border)'}}>
                      {t}
                    </span>
                  ))}
                </div>
                <span style={{color:'var(--accent)', fontSize:'18px'}}>→</span>
              </div>
            </Link>
          ))}
          {filtered.length === 0 && (
            <div style={{textAlign:'center', padding:'48px', color:'var(--text-muted)'}}>
              No workshops found
            </div>
          )}
        </div>

        {user && (
          <div className="wt-footer-cta">
            <Link to="/propose" className="btn btn-primary">
              ✏️ Propose a Workshop
            </Link>
          </div>
        )}
      </div>
    </div>
  );
}
